    const pq = new MinHeap();
    pq.enqueue(0, 0, 0);

    while (!pq.isEmpty()) {
        const { cost, node, state } = pq.dequeue();
        if (node === n - 1) {
            const ans = Math.min(dist0[n-1], dist1[n-1]);
            return ans === MAX_VALUE ? -1 : ans;
